@app.route('/api/documents', methods=['POST'])
def create_document():
    """Create a new document."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'No data provided'}), 400

    required_fields = ['title', 'content', 'author_id']
    for field in required_fields:
        if field not in data:
            return jsonify({'error': f'Missing required field: {field}'}), 400

    # Verify author exists
    try:
        author = users_collection.find_one({'_id': ObjectId(data['author_id'])})
        if not author:
            return jsonify({'error': 'Author not found'}), 404
    except Exception:
        return jsonify({'error': 'Invalid author_id'}), 400

    document = {
        'title': data['title'],
        'content': data['content'],
        'author_id': ObjectId(data['author_id']),
        'category': data.get('category', 'uncategorized'),
        'tags': data.get('tags', []),
        'status': data.get('status', 'draft'),  # draft, published, archived
        'metadata': data.get('metadata', {}),
        'version': 1,
        'version_history': [],
        'views': 0,
        'likes': 0,
        'comments_count': 0,
        'created_at': datetime.utcnow(),
        'updated_at': datetime.utcnow(),
        'published_at': None
    }

    if document['status'] == 'published':
        document['published_at'] = datetime.utcnow()

    try:
        result = documents_collection.insert_one(document)
        # Update user's document count
        users_collection.update_one(
            {'_id': ObjectId(data['author_id'])},
            {'$inc': {'document_count': 1}}
        )
        document['_id'] = str(result.inserted_id)
        return jsonify({'message': 'Document created successfully', 'document': serialize_doc(document)}), 201
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/documents', methods=['GET'])
def get_documents():
    """Get documents with filtering, sorting, and pagination."""
    # Query parameters
    status = request.args.get('status')
    category = request.args.get('category')
    author_id = request.args.get('author_id')
    tag = request.args.get('tag')
    sort_by = request.args.get('sort_by', 'created_at')
    sort_order = request.args.get('sort_order', 'desc')
    page = int(request.args.get('page', 1))
    per_page = int(request.args.get('per_page', 10))

    query = {}
    if status:
        query['status'] = status
    if category:
        query['category'] = category
    if author_id:
        try:
            query['author_id'] = ObjectId(author_id)
        except Exception:
            return jsonify({'error': 'Invalid author_id'}), 400
    if tag:
        query['tags'] = tag

    sort_direction = DESCENDING if sort_order == 'desc' else ASCENDING
    skip = (page - 1) * per_page
    total = documents_collection.count_documents(query)

    documents = list(
        documents_collection.find(query)
        .sort(sort_by, sort_direction)
        .skip(skip)
        .limit(per_page)
    )

    return jsonify({
        'documents': [serialize_doc(d) for d in documents],
        'total': total,
        'page': page,
        'per_page': per_page,
        'total_pages': (total + per_page - 1) // per_page
    }), 200


@app.route('/api/documents/search', methods=['GET'])
def search_documents():
    """Full-text search on documents."""
    search_query = request.args.get('q', '')
    status = request.args.get('status', 'published')
    page = int(request.args.get('page', 1))
    per_page = int(request.args.get('per_page', 10))

    if not search_query:
        return jsonify({'error': 'Search query is required'}), 400

    query = {
        '$text': {'$search': search_query},
        'status': status
    }

    skip = (page - 1) * per_page
    total = documents_collection.count_documents(query)

    documents = list(
        documents_collection.find(
            query,
            {'score': {'$meta': 'textScore'}}
        )
        .sort([('score', {'$meta': 'textScore'})])
        .skip(skip)
        .limit(per_page)
    )

    return jsonify({
        'documents': parse_json(documents),
        'total': total,
        'page': page,
        'per_page': per_page,
        'query': search_query
    }), 200


@app.route('/api/documents/<doc_id>', methods=['GET'])
def get_document(doc_id):
    """Get a specific document and increment view count."""
    try:
        document = documents_collection.find_one_and_update(
            {'_id': ObjectId(doc_id)},
            {'$inc': {'views': 1}},
            return_document=True
        )
        if not document:
            return jsonify({'error': 'Document not found'}), 404

        # Fetch author info
        author = users_collection.find_one(
            {'_id': document['author_id']},
            {'username': 1, 'full_name': 1, 'avatar_url': 1}
        )

        doc = serialize_doc(document)
        doc['author'] = serialize_doc(author) if author else None

        return jsonify({'document': doc}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 400


@app.route('/api/documents/<doc_id>', methods=['PUT'])
def update_document(doc_id):
    """Update a document with version tracking."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'No data provided'}), 400

    try:
        existing = documents_collection.find_one({'_id': ObjectId(doc_id)})
        if not existing:
            return jsonify({'error': 'Document not found'}), 404

        # Save current version to history
        version_entry = {
            'version': existing['version'],
            'title': existing['title'],
            'content': existing['content'],
            'updated_at': existing['updated_at']
        }

        allowed_fields = ['title', 'content', 'category', 'tags', 'status', 'metadata']
        update_data = {k: v for k, v in data.items() if k in allowed_fields}
        update_data['updated_at'] = datetime.utcnow()

        # Handle publishing
        if update_data.get('status') == 'published' and existing['status'] != 'published':
            update_data['published_at'] = datetime.utcnow()

        result = documents_collection.update_one(
            {'_id': ObjectId(doc_id)},
            {
                '$set': update_data,
                '$inc': {'version': 1},
                '$push': {'version_history': version_entry}
            }
        )

        document = documents_collection.find_one({'_id': ObjectId(doc_id)})
        return jsonify({'message': 'Document updated successfully', 'document': serialize_doc(document)}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 400


@app.route('/api/documents/<doc_id>', methods=['DELETE'])
def delete_document(doc_id):
    """Delete a document."""
    try:
        document = documents_collection.find_one({'_id': ObjectId(doc_id)})
        if not document:
            return jsonify({'error': 'Document not found'}), 404

        documents_collection.delete_one({'_id': ObjectId(doc_id)})

        # Decrement user's document count
        users_collection.update_one(
            {'_id': document['author_id']},
            {'$inc': {'document_count': -1}}
        )

        return jsonify({'message': 'Document deleted successfully'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 400


